mapper.select:
select
  count(*)
from goods_order gor
left join order_detail od on od.orderNo = gor.orderNo
where gor.userId = #{userId,jdbcType=BIGINT}
and gor.status = #{orderStatus}

select
userId,couponId,couponMoney
from goods_order WHERE orderNo=#{orderNo}

mapper.update:
    update goods_order
      set status = #{status}, finish = (case when 3 = #{status} then now() else finish end)
    where userId = #{userId,jdbcType=BIGINT}
	   and orderNo = #{orderNo,jdbcType=VARCHAR}
